The following index definition example uses the
sample\_mflix.movies collection to index a field as multiple types. The
following index definition indexes the `title` field as the following
types:

- `autocomplete` type to support autocompletion for queries using
  the [autocomplete](autocomplete-ref) operator.

- `string` type to support text search using operators such
  [text](text-ref), [Phrase](phrase-ref), and so on.

```javascript
const { MongoClient } = require("mongodb");

// connect to your Atlas deployment
const uri =  "<connection-string>";

const client = new MongoClient(uri);

async function run() {
  try {

    // set namespace
    const database = client.db("sample_mflix");
    const collection = database.collection("movies");

    // define your MongoDB Search index
    const index = {
      name: "default",
      definition: {
        /* search index definition fields */
        "mappings": {
          "dynamic": false,
          "fields": {
            "title": [{
              "type": "autocomplete",
              "analyzer": "lucene.standard",
              "tokenization": "edgeGram",
              "minGrams": 2,
              "maxGrams": 15,
              "foldDiacritics": false
            },
            {
              "type": "string",
            }]
          }
        }
      }
    }

    // run the helper method
    const result = await collection.createSearchIndex(index);
    console.log("New index name: " + result);
  } finally {
    await client.close();
  }
}

run().catch(console.dir);
